+    document.addEventListener('click', function(e) {
+        var btn = e.target.closest('.collapse-btn');
+        if (!btn) return;
+
+        e.preventDefault();
+        var panel = btn.closest('.panel');
+        if (!panel) return;
+
+        panel.classList.toggle('collapsed');
+    });
